var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_QM","text":{"KOREA":"어, 어째서 사람이 이런 곳에?","JPN":"ど、どうしてこんなところに人が？","ENG":"W-why is there a person here?","TWN":"這裡，怎麼會有人？"},"stage":{"bg":"VARUNA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_QM","text":{"KOREA":"아니, 살아 있기는 한 거야? 시체를 여기 놔둔 건 아니겠지?","JPN":"待って、そもそも生きているの？　まさか死体が置いてあるんじゃないわよね？","ENG":"Wait, is she even alive? Someone didn't just leave a corpse here, did they?","TWN":"等等，她還有呼吸嗎？不會是把屍體放在這裡吧？"},"stage":{"bg":"VARUNA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_QM","text":{"KOREA":"하지만…… 나침반의 바늘이 이 사람을 가리키고 있는데…….","JPN":"でも……やっぱり羅針盤の針はこの人を指している……","ENG":"But... I think the needle is pointing to her...","TWN":"可是……指南針上的針指向她……"},"stage":{"bg":"VARUNA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"이제 그만 포기해라.","JPN":"もう諦めろ。","ENG":"Give up now.","TWN":"你放棄吧。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_SERIOUS"},"R":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"내 망치에 곤죽이 되던가, 목숨이라도 부지해서 팔려 가던가.","JPN":"俺のハンマーの餌食になるか、命拾いする代わりに大人しく売り飛ばされるか。","ENG":"Make your choice. Either you get crushed by my hammer here, or we sell you off and you get to live another day.","TWN":"看你是要成為我的槌下亡魂，還是要留下小命被賣掉。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_SERIOUS"},"R":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"OVERFLOW_SCAVENGER_NULL_NULL","text":{"KOREA":"이 구석진 곳까지 몰렸으니 선택권은 그것뿐이다.","JPN":"ここまで追い込まれた以上、どっちかを選ぶしかねえ。","ENG":"We've got you cornered and those are your only choices.","TWN":"你躲在這個破爛地方，結果只有這二個。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_SERIOUS"},"R":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_QM","text":{"KOREA":"더 이상 빠져나갈 방법이 없어.","JPN":"もう逃げ場はない。","ENG":"There's no getting out of this.","TWN":"現在也沒其他方法可以逃出去，"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_HATE"},"R":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_QM","text":{"KOREA":"이대로 있으면 햄버거 패티가 되거나 팔려 가거나 둘 중 하나야……!","JPN":"このままだと、ミンチにされるか、売り飛ばされるかしかない……！","ENG":"It's either becoming a burger patty or getting sold as a slave...!","TWN":"繼續待在這裡，不是成為漢堡肉排，就是被抓去賣掉……！"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_IDLE"},"R":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_QM","text":{"KOREA":"곤히 자는 것 같은데 미안해요.","JPN":"お休みのところ、ごめんなさいね。","ENG":"You're sleeping so soundly, so I'm sorry about this.","TWN":"不好意思，打擾你睡覺，"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_DESPAIR"},"R":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_QM","text":{"KOREA":"하지만 당신, 분명 중요한 사람이겠죠?","JPN":"でもきっと、あなたって重要人物ですよね？","ENG":"But you must be someone important, right?","TWN":"不過你應該是什麼重要人物吧？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_IDLE"},"R":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_QM","text":{"KOREA":"당신이 누군지 모르겠지만, 이 나침반이 반응하는 사람이니까.","JPN":"あなたが誰かは知りませんけど、この羅針盤の針があなたを示していますから。","ENG":"I don't know who you are, but this compass is pointing to you.","TWN":"雖然我不認識你，但是指南針指著你。"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_SERIOUS"},"R":{"char_id":"OVERFLOW_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"생체 인증을 요구합니다.","JPN":"生体認証を行ってください。","ENG":"Requesting biometric authentication.","TWN":"進行生物辨識。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"생체 인증 유사도 측정……. ","JPN":"生体情報の類似度測定中…… ","ENG":"Checking biometric similarity...","TWN":"生物辨識相似度驗證中……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"권한 활성화.","JPN":"権限、活性化。","ENG":"Permission granted.","TWN":"啟用權限。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"인증 완료. 동결을 해제합니다.","JPN":"認証完了、凍結を解除します。","ENG":"Authentication complete. Initiating unfreezing process.","TWN":"辨識完畢，進行解凍。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_QM","text":{"KOREA":"여, 열렸다!","JPN":"ひ、開いた！","ENG":"I-it's open!","TWN":"打，打開咧！"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_QM","text":{"KOREA":"그, 근데 열리는 소리가 너무 크잖아! 이러면 애써 숨은 보람이 없다고!","JPN":"ていうか開く音大きすぎ！　これじゃ隠れた意味がないよ！","ENG":"B-but it's so loud! This will make hiding in here useless!","TWN":"但是也太大聲！這樣我辛辛苦苦躲起來幹嘛！"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"휘유~ 꽤 화려하게 위치를 알려줬네?","JPN":"ヒュウー！　こりゃ派手に居場所を教えてくれるじゃないか！","ENG":"Whoa! Now that's one way to tell us your location.","TWN":"唷呵～用這麼華麗的方式通知我你在哪嗎？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"혹시 관심받지 못하면 미쳐버리는 타입?","JPN":"もしかして、気を引きたくてどうしようもないタイプかな？","ENG":"Maybe you go insane if you don't get enough attention?","TWN":"難道是喜歡求關注的類型？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"나도 마찬가지야! 우린 정말 최고의 콤비가 될 것 같은데?","JPN":"それは俺も同じだ！　俺ら、マジで最高のコンビになりそうだぜ！","ENG":"Same here! I think we'll make a great combo!","TWN":"跟我一樣！我們好像可以成為好夥伴欸？"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"실험자와 실험체로 말이지!","JPN":"実験の実行者と被検体としてだけどな！","ENG":"The experimenter and the test subject!","TWN":"當然一個是實驗人，一個是實驗對象！"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_QM","text":{"KOREA":"제, 제발! 깨어나 주세요! 시간이 없어!","JPN":"は、早く！　起きて！　早くしないと！","ENG":"P-please! Wake up! There's no time!","TWN":"拜，拜託你醒醒吧！沒時間啦！"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};